<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="col-md-12  pt-3 px-0">
            <div class="row" v-show="isBillingType">
                <div class="col-md-8">
                    <dynamic-form lang="en" ref="validateRuleConfig" :buttons="false" v-show="isBillingType" :mandatorytext="$t('MandatoryString')" :schema="FormSchemaForUSIC"
                        >
                    </dynamic-form>
                    
                </div>
                <div class="col-lg-4">
                    <div class="listing mt-4">
                        <div class="table-responsive" style="overflow: auto; max-height: 400px;">
                            <table class="table table-bordered">
                                <thead class="thead-bg">
                                    <tr>
                                        <th width="50%">{{ $t("fieldName") }}</th>
                                        <th>{{ $t("DataType") }}</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    <tr v-for="(field, index) in groupFieldListOptions" :key="index">
                                        <td>{{ field.DISPLAY_NAME }}</td>
                                        <td>
                                             {{ field.DATA_TYPE.toLowerCase() === 'decimal' ? 'Decimal' : (field.DATA_TYPE.toLowerCase() === 'time' ? 'Time' : $t(field.DATA_TYPE)) }}
                                        </td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
             
                <div class="col-12 float-left my-3">
                    <div class="row flex-row-reverse">
                        <div class="col-lg-6 text-right">
                            <a title="Save" @click="OnSubmit" v-show="!mode" class="btn btn-success mr-2"><i class="fa fa-floppy-o pr-2" aria-hidden="true"></i>{{ $t("SaveAndNextWizard") }}</a>
                            <a title="Close" @click="Close"  class="btn btn-primary delete-btn"><i class="fa fa-times pr-2" aria-hidden="true"></i>{{ $t("Close") }} </a>    
                        </div>
                        <div class="col-lg-6">
                            <small class="py-2 mandatory">{{ $t('Mandatory') }}</small>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
    
import DataService from "../../../../services/DataService";
import {
    locateBillingService
} from "../../../../services/locateBillingService";

export default {
    props: {
        configurationId: {
            type: Number,
            required: false
        },
        serviceId: {
            type: Number,
            required: false
        },
        reqType: {
            type: String,
            required: false
        },
        isBillingType :{
            type: Boolean,
            required: false
        }
    },
    data() {
        return {
            isLoading: false,
            ruleServiceList:[],
            BindUtilityName:[],
            FormSchemaForUSIC: [
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('BillingTemplateName'),
                            name: "BillingTemplateName",
                            value: "",
                            placeholder: 'Enter Billing Rule Name',
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('CompanyName'),
                            name: "CompanyName",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('PricingMethod'),
                            name: "PricingMethod",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('GroupByForApplyingCharge'),
                            name: "GroupByForApplyingCharge",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('ComboChargeScope'),
                            name: "ComboChargeScope",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": false, max: 100 },
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('SaveAndNextWizard'),
                    isVisible: true,

                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.Close,
                }
            ],
            serviceList:[],
            mode :false,
            groupFieldListOptions:[],
            setupId :32,
            chargeTypeList:[]
        }
    },
    created: async function () {
        let vm = this;
        if(this.$route.params.mode =='View'){
            vm.mode = true;
        }
        var timeZone = this.GetUserInfo.TimeZone;
        await vm.GetDDLCompanyList();
        await vm.GetComboChargesListBySetupId(vm.setupId);
        await vm.GetFieldsListBySetupId(vm.setupId);
        await vm.GetBillingChargeTypeList();
        if (vm?.configurationId) {
            await vm.BindConfigurationData(vm.configurationId,vm.serviceId,timeZone);
        }
        if (vm.mode) {
            vm.FormSchemaForUSIC.forEach(section => {
                section.Data.forEach(field => {
                    field.disabled = true;
                });
            });
            vm.buttons.forEach(btn => {
                if (btn.type === 'submit') {
                    btn.isVisible = false; 
                }
            });
        }
    },
    methods: {
        Close() {
            var vm = this;
            vm.$router.push({name: vm.isBillingType ? 'BillingRule' : 'BillingRuleListing'});
        },
        GetDDLCompanyList: async function () {
            var vm = this;
            await DataService.GetDdlCompanyList().then((response) => {
                if (response.data != '') {
                    if (response.data.length) {
                        const optionsArray = response.data.map(element => ({
                            name: element.Company_Name,
                            value: element.company_id
                        }));
                        vm.FormSchemaForUSIC[0].Data[1].config.options= optionsArray;
                        // vm.$refs.validateRuleConfig.updateProperty("CompanyName", "config.options", optionsArray);
                        vm.$refs.validateRuleConfig.UpdateKeyValue();
                    }
                }
            })
        },
        GetBillingChargeTypeList: async function () {
            var vm = this;
            vm.chargeTypeList=[];
            await DataService.GetBillingChargeTypeList().then((response) => {
                if (response.data != '') {
                    if (response.data.length) {

                        const optionsArray = response.data.map(element => ({
                            name: element.CATEGORY_NAME,
                            value: element.CATEGORY_ID
                        }));
                        vm.chargeTypeList = optionsArray;
                        vm.FormSchemaForUSIC[0].Data[2].config.options= optionsArray;
                        // vm.$refs.validateRuleConfig.updateProperty("PricingMethodId", "config.options", optionsArray);
                        vm.$refs.validateRuleConfig.UpdateKeyValue();
                    }
                }
            })
        },
        
        GetFieldsListBySetupId: async function (setupId) {
            var vm = this;
            var url = `setupId=${setupId}&isGroupBy=true&reqFrom=`;
            await DataService.GetFieldsListBySetupId(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    const optionsArray = JSON.parse(response.data).map(element => ({
                            name: element.DISPLAY_NAME,
                            value: element.TEMPLATE_ID
                        }));
                    vm.FormSchemaForUSIC[1].Data[0].config.options= optionsArray;
                    // vm.$refs.validateRuleConfig.updateProperty("GroupByForApplyingCharge", "config.options", optionsArray);
                    vm.$refs.validateRuleConfig.UpdateKeyValue();
                }
            });
            await vm.BindFieldListBySetupId(setupId);
        },
        BindFieldListBySetupId: async function(setupId){
            var vm = this;
            vm.groupFieldListOptions=[];
            var url = `setupId=${setupId}&reqFrom=`;
            await DataService.GetFieldsListBySetupId(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    vm.groupFieldListOptions = JSON.parse(response.data);
                }
            });
        },
        GetComboChargesListBySetupId: async function (setupId) {
            var vm = this;
            var url = `setupId=${setupId}&isComboChargeScope=true&reqFrom=`;
            await DataService.GetFieldsListBySetupId(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    const optionsArray = JSON.parse(response.data).map(element => ({
                            name: element.DISPLAY_NAME,
                            value: element.TEMPLATE_ID
                        }));
                    vm.FormSchemaForUSIC[1].Data[1].config.options= optionsArray;
                    // vm.$refs.validateRuleConfig.updateProperty("ComboChargeScope", "config.options", optionsArray);
                    vm.$refs.validateRuleConfig.UpdateKeyValue();
                }
            });
        },
        BindConfigurationData: async function (configurationId,serviceId,timeZone) {
            var vm = this;
            this.isLoading = true;
            const url = `configrationId=${configurationId}&serviceId=${serviceId}&timezone=${timeZone}`;
            const response = await DataService.BindBillingRuleTemplateById(url);
            if (response && response.data != null) {
                var configurationValue = response.data;
                    this.FormSchemaForUSIC.forEach(function(grpItem){
                    grpItem.Data.forEach(function(item){
                        switch (item.name) {
                            case "BillingTemplateName":
                                item.value = configurationValue.billingTemplateName;
                                break;
                            case "CompanyName":
                                item.value = configurationValue.companyId;
                                break;
                            case "GroupByForApplyingCharge":
                                item.value = configurationValue.groupBy;
                                break;
                            case "ComboChargeScope":
                                item.value = configurationValue.comboChargeScope;
                                break;
                            case "PricingMethod":
                                item.value = configurationValue.pricingMethodId;
                                break;
                        }
                    });
                });   
                this.isLoading = false;
            }
        },
        async OnSubmit(formfields, val) {
            var vm = this;
            const result = await vm.$refs.validateRuleConfig.validateForm.validate();
            if (result) {
                const ref = vm.$refs.validateRuleConfig;
                let payload = {};
                // 🔹 BILLING TYPE (USIC)
             
                    const utilityList = ref.getPropertyValue("UtilityName", "value"),
                    selectedText = utilityList
                        ?.map(v => vm.BindUtilityName?.find(u => u.value === v)?.text)
                        .filter(Boolean)
                        .join(", ");

                    const chargeTypeId = ref.getPropertyValue("ChargeTypeId", "value")
                    const chargeType = vm.chargeTypeList?.find(u => u.value === chargeTypeId);
                    payload = {
                        configurationId: vm.configurationId ? vm.configurationId : 0,
                        billingRuleName: ref.getPropertyValue("BillingRuleName", "value"),
                        companyId: ref.getPropertyValue("CompanyName", "value"),
                        groupBy: ref.getPropertyValue("GroupByForApplyingCharge", "value"),
                        chargeType: chargeType.name.toLowerCase(),
                        chargeTypeId: chargeTypeId,
                        comboChargeScope: ref.getPropertyValue("ComboChargeScope", "value"),
                        utilityNameText : selectedText,
                        isBillingType : true,
                        setupId: this.setupId
                    };
                
                var params = JSON.stringify(payload);
                DataService.SaveBillingRuleConfiguration(params).then((response) => {
                    if (response.data.status == "Success" && response.data.code == "1") {
                        vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Configuration")]), "success", true, vm.$t("Alert"));
                        setTimeout(function () {
                            if(vm.reqType !== 'fromServiceMapping' && vm.isBillingType === false){
                                vm.$router.push({ name: 'NodeTemplateConfiguration', params: { id: response.data.result,serviceId : response.data.linkedId } });
                            }
                            else if(vm.reqType !== 'fromServiceMapping' && vm.isBillingType === true){
                                vm.$router.push({ name: 'NodeTemplateConfiguration', params: { id: response.data.result,serviceId : response.data.linkedId,mode:'Add' } });
                            }
                            vm.$emit('config-saved', { configId: response.data.result, goTo: 'NodeConfiguration' });
                        }, 200);
                    }
                    else if (response.data.status == "Success" && response.data.code == "2") {
                        vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t("Configuration")]), "success", true, vm.$t("Alert"));
                    }
                    else if (response.data.status == "Success" && response.data.code == "3") {
                        vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Configuration')]), "failure", true, vm.$t('Alert'));
                    }
                });

            }
            
        }
    }
}
</script>