<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ refCode === 'Update' ? $t('UpdateLimit') : $t('AddLimit') }}
                            </h5>
                            <button type="button" class="close" @click="CloseLimit">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;" role="button" aria-expanded="false" aria-controls="collapseExample">
                                    <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                                </a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con"  v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validateLimit" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                                <template v-slot:tgslot-Limit="{ data }">


                                    <Field name="Limit" :rules="{ 'required': true }" v-slot="{ errors }">
                                        <div class="input-group">
                                            <input type="number" id="" v-model="data.fieldInfo.value" min="1"
                                                maxlength="365" v-bind:class="{ 'txtitems form-control ': true, }" />
                                        </div>
                                        <span v-if="errors[0]" name="Limit" class="invalid-feedback d-block">{{
                                            errors[0]
                                            }}</span>

                                    </Field>
                                </template>
                                <template v-slot:tgslot-DayLimit="{ data }">


                                    <Field name="DayLimit" :rules="{ 'required': true }" v-slot="{ errors }">
                                        <div class="input-group">
                                            <input type="number" id="" v-model="data.fieldInfo.value" min="1"
                                                maxlength="365" v-bind:class="{ 'txtitems form-control ': true, }" />

                                        </div>
                                        <span v-if="errors[0]" name="DayLimit" class="invalid-feedback d-block">{{
                                            errors[0]
                                            }}</span>

                                    </Field>
                                </template>
                            </dynamic-form>
                        </div>

                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from '../../../../services/DataService';
import {
    locateBillingService
} from "../../../../services/locateBillingService";


export default {
    props: {
        callbackfunction: {
            type: Function,
            required: false
        },
        refCode: {
            type: String,
            required: false
        },
        EditLimitData: {
            type: Object,
            required: false
        },
        configurationId: {
            type: String,
            required: false
        },
        clientId:{
            type: Number,
            required: false
        },
        mode: {
            type: String,
            default: 'Edit'
        }
    },
    data() {

        return {
            isLoading: false,
            id: 0,
            isVisibleUtility: true,
            clientsIds: '',
            type: "",
            isShown: false,
            FormSchema: [
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('WorkCode'),
                            name: "WorkCode",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('AlternateWorkCode'),
                            name: "AlternateWorkcode",
                            value: "",
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('LimitValue'),
                            name: "Limit",
                            value: "",
                            placeholder: '',
                            validationRules: { "required": false, max: 365 },
                            visibility: true,
                        }

                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('DayLimit'),
                            name: "DayLimit",
                            value: "",
                            placeholder: '',
                            validationRules: { "required": false, max: 365 },
                            visibility: true,
                        }
                    ]
                },

            ],
        }
    },
    computed: {
        buttons() {
            const baseButtons = [
                {
                    type: "submit",
                    class: "btn btn-success",
                    visibility: true,
                    title: this.$t('Update'),
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Update'),
                    onClick: this.SubmitData,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    type: "button",
                    title:this.$t('Cancel'),
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseLimit,
                },
            ];
            
            // Hide Save buttons when mode is View - filter out submit buttons
            if (this.mode === 'View') {
                return baseButtons.filter(btn => btn.type !== 'submit');
            }
            
            return baseButtons;
        }
    },
    created: async function () {
        var vm = this;
        await vm.GetDdlWorkCode();
    },
    mounted() {
        if (this.EditLimitData && Object.keys(this.EditLimitData).length > 0 && this.refCode == 'Update') {
            this.BindEditDetail(this.EditLimitData);
        }
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    methods: {
        getUserGuideTitle() {
            let text = this.$t('UserGuide_billing_limit_Add');
            return text
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },
        BindEditDetail: function(data) {
            var vm = this;
            vm.id = data.limitId;
            vm.configurationId != null ? vm.configurationId : 0;
            vm.$refs.validateLimit.updateProperty("WorkCode", "value", data.workCodeId);
            vm.$refs.validateLimit.updateProperty("AlternateWorkcode", "value", data.alternateWorkCodeId);
            vm.$refs.validateLimit.updateProperty("Limit", "value", data.limitValue);
            vm.$refs.validateLimit.updateProperty("DayLimit", "value", data.dayLimit);
            vm.$refs.validateLimit.UpdateKeyValue();
        },
        GetDdlWorkCode: async function () {
            var vm = this;
            vm.isLoading = true;
            await DataService.GetWorkCodeInfo().then((response) => {
                if (response.data != '' && response.data != null) {
                    var selctedValue = [];
                    if (response.data.length > 0) {
                        response.data.forEach((item, index) => {
                            selctedValue.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                    vm.$refs.validateLimit.updateProperty("WorkCode", "config.options", selctedValue);
                    vm.$refs.validateLimit.updateProperty("AlternateWorkcode", "config.options", selctedValue);
                    vm.$refs.validateLimit.UpdateKeyValue();
                }
            });
            vm.isLoading = false;
        },
        SubmitData: async function (event) {
            var vm = this;
            vm.isLoading = true;
            const result = await vm.$refs.validateLimit.validateForm.validate();
            if (!result) {
                this.isLoading = false;
                return;
            }
            const limitId = vm.id == 0 ? 0 : vm.id;
            const ConfigId = vm.configurationId != null ? vm.configurationId : 0;
            const WorkCodeId = vm.$refs.validateLimit.getPropertyValue("WorkCode", "value");
            const AlternateWorkCodeId = vm.$refs.validateLimit.getPropertyValue("AlternateWorkcode", "value");
            const LimitValue = vm.$refs.validateLimit.getPropertyValue("Limit", "value");
            const DayLimit = vm.$refs.validateLimit.getPropertyValue("DayLimit", "value");
            var obj = {
                limitId: limitId,
                client_id : vm.clientId,
                configuration_id: ConfigId,
                workcode_id: WorkCodeId,
                alternate_code: AlternateWorkCodeId,
                limit: LimitValue,
                limit_days: DayLimit
            }
            var jsondata = JSON.stringify(obj);
            var url = `Data=${jsondata}`;
            await DataService.CreateLimit(url).then((response) => {
                if (response.data != '') {
                    if (response.data[0].STATUS_CODE == 1 && vm.id == 0) {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('LimitValue')]), "Success", true, vm.$t('Alert'));
                        vm.callbackfunction();
                        vm.ResetModel();
                        vm.CloseLimit();

                    }
                    else if (response.data[0].STATUS_CODE == 1 && vm.id > 0) {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('LimitValue')]), "Success", true, vm.$t('Alert'))
                        vm.callbackfunction();
                        vm.CloseLimit();

                    }
                    else {
                        vm.ShowAlert(vm.$t("ErrorWhileSaving", [vm.$t("LimitValue")]), "danger", true, vm.$t("Alert"));
                    }
                }
                vm.isLoading = false;
            });
        },
        ResetModel() {
            var vm = this;
            vm.$refs.validateLimit.updateProperty("WorkCode", "value", "");
            vm.$refs.validateLimit.updateProperty("AlternateWorkcode", "value", "");
            vm.$refs.validateLimit.updateProperty("Limit", "value", "");
            vm.$refs.validateLimit.updateProperty("DayLimit", "value", "");
        },
        CloseLimit() {
            this.$emit('CloseLimit');
        },
    },
}
</script>

<style lang="scss" scoped></style>